path is staged, rebases before push, and **always exits 0** so it can never trip Pulse's 3-failure breaker.

```ts
#!/usr/bin/env bun
// Daily git auto-commit for knowledge/docs repos only. Explicit allowlist.
import { $ } from "bun"

const HOME = process.env.HOME ?? ""
// ALLOWLIST: notes/docs/config repos only. NOT code repos, NOT worktrees.
const REPOS = [
  `${HOME}/Documents/workspace`,        // life-os
  // `${HOME}/.claude`,                 // enable once it is a git repo on the box
]
const SECRET = [REDACTED])\.env|\.key$|\.pem$|id_rsa|\.secrets\//
const stamp = new Date().toISOString().slice(0, 16).replace("T", " ")
const host = (await $`hostname -s`.quiet().text()).trim()

for (const dir of REPOS) {
  try {
    await $`git -C ${dir} rev-parse --git-dir`.quiet()
    // skip if mid-merge/rebase
    const inMerge = await $`git -C ${dir} rev-parse -q --verify MERGE_HEAD`.quiet().nothrow()
    if (inMerge.exitCode === 0) { console.log(`SKIP ${dir}: mid-merge`); continue }

    const dirty = (await $`git -C ${dir} status --porcelain`.quiet().text()).trim()
    if (!dirty) { console.log(`clean ${dir}`); continue }

    await $`git -C ${dir} add -A`.quiet()
    const staged = (await $`git -C ${dir} diff --cached --name-only`.quiet().text()).trim().split("\n")
    const leak = staged.find((f) => SECRET.test(f))
    if (leak) { await $`git -C ${dir} reset`.quiet(); console.log(`ABORT ${dir}: secret staged (${leak})`); continue }

    await $`git -C ${dir} commit -m ${`chore: daily auto-commit ${stamp} (${host})`}`.quiet()
    const hasUpstream = await $`git -C ${dir} rev-parse --abbrev-ref --symbolic-full-name @{u}`.quiet().nothrow()
    if (hasUpstream.exitCode === 0) {
      await $`git -C ${dir} pull --rebase --autostash`.quiet().nothrow()
      const push = await $`git -C ${dir} push`.quiet().nothrow()
      console.log(push.exitCode === 0 ? `pushed ${dir}` : `committed (push FAILED, retry next run) ${dir}`)
    } else {
      console.log(`committed (no upstream) ${dir}`)
    }
  } catch (e) { console.log(`ERROR ${dir}: ${e}`) }
}
process.exit(0)   // never fail the Pulse job
```

### Step 2 - Initial cleanup commit (the 5-ahead + dirty state you approved)
```bash
bun ~/.claude/PAI/TOOLS/GitAutoCommit.ts      # commits + pushes life-os, brings GitHub current
git -C ~/Documents/workspace log --oneline -1 # verify
```

### Step 3 - Schedule it daily (Pulse job - travels to the box automatically)
Add to `~/.claude/PAI/Pulse/PULSE.toml`:
```toml
[[job]]
name = "git-autocommit"
schedule = "30 23 * * *"          # daily 23:30, after the diary job
type = "script"
command = "bun run $HOME/.claude/PAI/TOOLS/GitAutoCommit.ts"
output = "log"
enabled = true
```
Then reload and verify (using the reliable restart, not `manage.sh restart`):
```bash
launchctl kickstart -k gui/$(id -u)/com.pai.pulse
~/.claude/PAI/Pulse/manage.sh status          # git-autocommit should appear after its first run
```

### Step 4 - Home-box portability
Because it is a `TOOLS/` script plus a Pulse job, it rides in the `~/.claude` repo with everything else. On the box it needs nothing extra. The one addition there: once `~/.claude` is its own git repo on the box, uncomment the `~/.claude` line in `REPOS`.

### Step 5 - Runbook fix
Correct the `home-box.md` DR line that wrongly says workspace syncs via OneDrive: workspace is the `life-os` GitHub repo, kept current by this job.

### Step 6 - Verify it actually works
- `bun ~/.claude/PAI/TOOLS/GitAutoCommit.ts` prints `pushed` / `clean` per repo, exit 0.
- The commit shows on GitHub.
- Next day, `manage.sh status` shows `git-autocommit: ... (ok)`.

